 2705 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
 2706 |     function applyLocalPatch(content, ops) {
 2707 |         let lines = content.split('\n');
 2708 |         let logs = [];
 2709 |         let success = true;
 2710 | 
 2711 |         if (typeof ops === 'string') {
 2712 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
 2713 |         }
 2714 | 
 2715 |         ops.forEach(op => {
 2716 |             if (op.action === 'comment') return;
 2717 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
 2718 |             
 2719 |             if (op.action === 'replace_block') {
 2720 |                 // Strategy 1: Exact String Match (Fastest)
 2721 |                 const currentStr = lines.join('\n');
 2722 |                 if (currentStr.includes(op.find_block)) {
 2723 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
 2724 |                     logs.push('Exact match applied');
 2725 |                     return;
 2726 |                 }
 2727 | 
 2728 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
 2729 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
 2730 |                 if (searchLines.length === 0) return;
 2731 | 
 2732 |                 let matchStart = -1;
 2733 |                 let matchEnd = -1;
 2734 | 
 2735 |                 // Scan file lines
 2736 |                 for (let i = 0; i < lines.length; i++) {
 2737 |                     // If first line matches (ignoring whitespace)
 2738 |                     if (lines[i].trim() === searchLines[0]) {
 2739 |                         // Check subsequent lines
 2740 |                         let allMatch = true;
 2741 |                         let fileOffset = 0;
 2742 |                         let searchOffset = 1;
 2743 |                         
 2744 |                         while (searchOffset < searchLines.length) {
 2745 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
 2746 |                             const nextFile = lines[i + fileOffset + 1].trim();
 2747 |                             // Skip empty lines in file if they aren't in search block
 2748 |                             if (nextFile === '') {
 2749 |                                 fileOffset++;
 2750 |                                 continue;
 2751 |                             }
 2752 |                             if (nextFile !== searchLines[searchOffset]) {
 2753 |                                 allMatch = false;
 2754 |                                 break;
 2755 |                             }
 2756 |                             fileOffset++;
 2757 |                             searchOffset++;
 2758 |                         }
 2759 | 
 2760 |                         if (allMatch) {
 2761 |                             matchStart = i;
 2762 |                             matchEnd = i + fileOffset;
 2763 |                             break;
 2764 |                         }
 2765 |                     }
 2766 |                 }
 2767 | 
 2768 |                 if (matchStart !== -1) {
 2769 |                     // Replace the range of lines
 2770 |                     const replacement = op.replace_with.split('\n');
 2771 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
 2772 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
 2773 |                 } else {
 2774 |                     success = false;
 2775 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
 2776 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
 2777 |                 }
 2778 |             }
 2779 |         });
 2780 |         return { content: lines.join('\n'), success, logs };
 2781 |     }
