 2789 | 
 2790 |         // Fix one by one (recursive loop)
 2791 |         async function fixNext(index) {
 2792 |             if (index >= currentErrors.length) return true; // All initial errors processed
 2793 | 
 2794 |             const err = currentErrors[index];
 2795 |             status.innerText = `🔧 Fixing Error ${index + 1}/${currentErrors.length} (Line ${err.line})...`;
 2796 |             status.style.color = "#eab308"; // Dev yellow
 2797 | 
 2798 |             try {
 2799 |                 // 1. Get Patch from AI
 2800 |                 const res = await fetch(CONFIG.funcUrl, { 
 2801 |                     method: 'POST', 
 2802 |                     headers: {'Content-Type': 'application/json'},
 2803 |                     body: apiBody({ 
 2804 |                         action: 'propose_syntax_fix', 
 2805 |                         code: currentCode, 
 2806 |                         error: err 
 2807 |                     })
 2808 |                 });
 2809 |                 const data = await res.json();
 2810 |                 const ops = data.operations;
 2811 | 
 2812 |                 if (!ops || ops === "[]") throw new Error("AI could not generate a fix.");
 2813 | 
 2814 |                 // 2. Apply Patch Locally
 2815 |                 const patchResult = applyLocalPatch(currentCode, ops);
 2816 |                 if (!patchResult.success) throw new Error("Generated patch did not match code.");
 2817 | 
 2818 |                 currentCode = patchResult.content;
 2819 |                 document.getElementById('ef-code').value = currentCode; // Update UI
 2820 | 
 2821 |                 // 3. Re-Validate
 2822 |                 const scanRes = await fetch(CONFIG.funcUrl, { 
 2823 |                     method: 'POST', headers: {'Content-Type': 'application/json'},
 2824 |                     body: apiBody({ action: 'validate_syntax_deep', code_block: currentCode, file_path: 'index.ts' })
 2825 |                 });
 2826 |                 const scanData = await scanRes.json();
 2827 | 
 2828 |                 if (scanData.valid) {
 2829 |                     status.innerText = "✅ Syntax Fixed!";
 2830 |                     return true;
 2831 |                 } else {
 2832 |                     // If errors remain, update list and Prompt user
 2833 |                     currentErrors = scanData.errors;
 2834 |                     if (confirm(`Fix applied, but ${currentErrors.length} errors remain. Continue fixing?`)) {
 2835 |                         // Recursively fix the *new* first error (since layout changed)
 2836 |                         return await fixNext(0);
 2837 |                     } else {
 2838 |                         return false;
 2839 |                     }
 2840 |                 }
 2841 | 
 2842 |             } catch (e) {
 2843 |                 if (confirm(`Auto-Fix Failed: ${e.message}\n\nTry again?`)) {
 2844 |                     return await fixNext(index);
 2845 |                 } else {
 2846 |                     return false;
 2847 |                 }
 2848 |             }
 2849 |         }
 2850 | 
 2851 |         return await fixNext(0);
 2852 |     }
