 6427 |     function timeAgo(dateString) {
 6428 |         const date = new Date(dateString);
 6429 |         const now = new Date();
 6430 |         const seconds = Math.floor((now - date) / 1000);
 6431 |         if (seconds < 10) return 'just now';
 6432 |         if (seconds < 60) return seconds + 's ago';
 6433 |         const minutes = Math.floor(seconds / 60);
 6434 |         if (minutes < 60) return minutes + 'm ago';
 6435 |         const hours = Math.floor(minutes / 60);
 6436 |         if (hours < 24) return hours + 'h ago';
 6437 |         return date.toLocaleDateString();
 6438 |     }
