 6700 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
 6701 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
 6702 |         
 6703 |         const navItems = document.querySelectorAll('.nav-item');
