 6705 | 
 6706 |         const scrollContainer = document.querySelector('.main-view');
 6707 |         let retryCount = 0;
 6708 |         const MAX_RETRIES = 5;
 6709 | 
 6710 |         const attemptNavigation = async () => {
 6711 |             const element = document.querySelector(selector);
 6712 |             
 6713 |             if (element) {
 6714 |                 console.log("[DeepJump] Element found. Scrolling...");
 6715 |                 
 6716 |                 // Wait for any tab transition animations
 6717 |                 await new Promise(r => setTimeout(r, 300));
 6718 | 
 6719 |                 let offsetTop = 0;
 6720 |                 let curr = element;
 6721 |                 while (curr && curr !== scrollContainer) {
 6722 |                     offsetTop += curr.offsetTop;
 6723 |                     curr = curr.offsetParent;
 6724 |                 }
 6725 | 
 6726 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
 6727 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
