 6736 |                 }, 3000);
 6737 |                 
 6738 |                 console.groupEnd();
 6739 |                 return true;
 6740 |             }
 6741 | 
 6742 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
 6743 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
 6744 |                 retryCount++;
 6745 |                 showGlobalToast("🔍 Searching deeper...");
 6746 |                 
 6747 |                 await loadMoreFn(); 
 6748 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
 6749 |                 return attemptNavigation();
