 9594 |             if (sqlHistory.length > 50) {
 9595 |                 sqlHistory.shift();
 9596 |                 sqlHistoryIndex--;
 9597 |             }
 9598 | 
 9599 |             // Debounce storage write
 9600 |             clearTimeout(saveSqlStateTimeout);
 9601 |             saveSqlStateTimeout = setTimeout(() => {
 9602 |                 persistSqlHistory();
