// 2. Rewrite external <script type="module" src="..."> tags into inline imports
// This forces the browser to resolve the entry point path via the import map,
// bypassing standard blob-relative resource fetch limitations.
doc.querySelectorAll('script[type="module"][src]').forEach(script => {
    const src = script.getAttribute('src');
    if (src) {
        const inlineScript = doc.createElement('script');
        inlineScript.type = 'module';
        // Convert to a bare specifier to bypass relative URL resolution on opaque origins
        const bareSrc = src.replace(/^(\.\/|\/)/, ''); 
        inlineScript.textContent = `import "${bareSrc}";`;
        script.replaceWith(inlineScript);
    }
});

