 2217 |     /**
 2218 |      * Converts a JSON operations array back into CXP XML Markup.
 2219 |      */
 2220 |     function operationsToCXP(ops) {
 2221 |         if (!Array.isArray(ops)) ops = ops.operations || [];
 2222 |         if (!Array.isArray(ops) || ops.length === 0) return "";
 2223 |         
 2224 |         let xmlOutput = "";
 2225 |         let comments = [];
 2226 | 
 2227 |         // Obfuscate tags to prevent the IDE's own CXP regex parser from intercepting them
 2228 |         const t = {
 2229 |             rb: '<re' + 'place_block', rbe: '</re' + 'place_block>',
 2230 |             f: '<fi' + 'nd>', fe: '</fi' + 'nd>',
 2231 |             rw: '<re' + 'place_wi' + 'th>', rwe: '</re' + 'place_wi' + 'th>',
 2232 |             cf: '<cre' + 'ate_file', cfe: '</cre' + 'ate_file>',
 2233 |             df: '<del' + 'ete_file',
 2234 |             c: '<com' + 'ment>', ce: '</com' + 'ment>',
 2235 |             cnt: '<con' + 'tent>', cnte: '</con' + 'tent>'
 2236 |         };
 2237 | 
 2238 |         ops.forEach(op => {
 2239 |             if (op.action === 'comment') {
 2240 |                 if (op.text) comments.push(op.text);
 2241 |             } else if (op.action === 'replace_block') {
 2242 |                 xmlOutput += `\n${t.rb} file="${op.file_path || op.file}">\n${t.f}\n${op.find_block || op.find}\n${t.fe}\n${t.rw}\n${op.replace_with || op.replace}\n${t.rwe}\n${t.rbe}\n`;
 2243 |             } else if (op.action === 'create_file') {
 2244 |                 xmlOutput += `\n${t.cf} file="${op.file_path || op.file}">\n${t.cnt}\n${op.content}\n${t.cnte}\n${t.cfe}\n`;
 2245 |             } else if (op.action === 'delete_file') {
 2246 |                 xmlOutput += `\n${t.df} file="${op.file_path || op.file}" />\n`;
 2247 |             }
 2248 |         });
 2249 | 
 2250 |         const finalComment = comments.length > 0 ? comments.join('\n---\n') : 'Recovered XML Payload';
 2251 |         return `${t.c}\n${finalComment}\n${t.ce}\n${xmlOutput}`.trim();
 2252 |     }
