 2264 |         console.log("Raw Input Length:", input.length, "characters");
 2265 |         
 2266 |         const operations = [];
 2267 | 
 2268 |         const cleanContent = (txt) => {
 2269 |             return txt.replace(/^\r?\n/, '').replace(/\r?\n\s*$/, '');
 2270 |         };
 2271 | 
 2272 |         // 1. Extract Top-level Comments
 2273 |         const commentMatch = input.match(/<comment>([\s\S]*?)<\/comment>/i);
 2274 |         if (commentMatch) {
 2275 |             console.log("✅ Comment Extracted:", commentMatch[1].trim());
 2276 |             operations.push({
 2277 |                 action: 'comment',
 2278 |                 text: commentMatch[1].trim()
 2279 |             });
 2280 |         } else {
 2281 |             console.warn("⚠️ No <comment> tag found.");
 2282 |         }
 2283 | 
 2284 |         // 2. Extract Replace Blocks (Robust regex supporting attributes in any order and single/double quotes)
 2285 |         const replaceRegex = /<replace_block[^>]*(?:file|file_path)\s*=\s*['"]([^'"]+)['"][^>]*>([\s\S]*?)<\/replace_block>/gi;
 2286 |         let match;
 2287 |         let replaceCount = 0;
 2288 |         
 2289 |         while ((match = replaceRegex.exec(input)) !== null) {
