 2291 |             const filePath = match[1].trim();
 2292 |             const inner = match[2];
 2293 |             
 2294 |             const findMatch = inner.match(/<find>([\s\S]*?)<\/find>/i);
 2295 |             const replaceWithMatch = inner.match(/<replace_with>([\s\S]*?)<\/replace_with>/i);
 2296 | 
 2297 |             console.log(`[Replace Block #${replaceCount}] Found target file:`, filePath);
 2298 |             
 2299 |             if (!findMatch) console.error(`❌ [Replace Block #${replaceCount}] Failed to find <find>...</find> tags!`);
 2300 |             if (!replaceWithMatch) console.error(`❌ [Replace Block #${replaceCount}] Failed to find <replace_with>...</replace_with> tags!`);
 2301 | 
 2302 |             if (filePath && findMatch && replaceWithMatch) {
 2303 |                 console.log(`✅ [Replace Block #${replaceCount}] Parsed successfully!`);
 2304 |                 operations.push({
 2305 |                     action: 'replace_block',
