 5793 |         toast.style.cssText = "position:fixed; bottom:100px; left:50%; transform:translateX(-50%); background:#333; color:white; padding:10px 20px; border-radius:30px; z-index:9999; font-size:12px;";
 5794 |         document.body.appendChild(toast);
 5795 | 
 5796 |         try {
 5797 |             // 1. Get the jobs for this run to find the build job
 5798 |             const resJobs = await fetch(CONFIG.funcUrl, { 
 5799 |                 method: 'POST', 
 5800 |                 headers: {'Content-Type': 'application/json'}, 
 5801 |                 body: apiBody({ action: 'fetch_workflow_jobs', run_id: runId }) 
 5802 |             });
 5803 |             const dataJobs = await resJobs.json();
 5804 |             
 5805 |             // Look for a job that likely uploaded artifacts (usually named 'build' or is the successful one)
 5806 |             const buildJob = dataJobs.jobs.find(j => j.name.toLowerCase().includes('build') || j.conclusion === 'success');
 5807 |             
 5808 |             if (!buildJob) {
 5809 |                 toast.remove();
 5810 |                 return alert("Could not identify the build job for this run.");
 5811 |             }
 5812 | 
 5813 |             // 2. Fetch the logs for that specific job
 5814 |             const resLogs = await fetch(CONFIG.funcUrl, { 
