 5816 |                 headers: {'Content-Type': 'application/json'}, 
 5817 |                 body: apiBody({ action: 'fetch_job_logs', job_id: buildJob.id }) 
 5818 |             });
 5819 |             const dataLogs = await resLogs.json();
 5820 |             const logs = dataLogs.logs || "";
 5821 | 
 5822 |             // 3. Extract the URL using Regex (looking for the specific pattern in your logs)
 5823 |             // Pattern: Artifact download URL: https://github.com/...
 5824 |             const urlMatch = logs.match(/Artifact download URL:\s*(https?:\/\/[^\s]+)/);
 5825 | 
 5826 |             if (urlMatch && urlMatch[1]) {
 5827 |                 toast.style.background = "var(--prod)";
