 6418 |     // --- GENERIC UI ---
 6419 |     function formatBytes(bytes) {
 6420 |         if (!bytes) return '0 B';
 6421 |         const k = 1024;
 6422 |         const sizes = ['B', 'KB', 'MB', 'GB'];
 6423 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
 6424 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
 6425 |     }
