 9587 |         if (sqlHistoryIndex === -1 || sqlHistory[sqlHistoryIndex] !== val) {
 9588 |             // If we are editing in the middle of history, clear forward history (standard undo/redo behavior)
 9589 |             sqlHistory = sqlHistory.slice(0, sqlHistoryIndex + 1);
 9590 |             sqlHistory.push(val);
