 9941 |     function extractTableNames(sql) {
 9942 |         if (!sql) return [];
 9943 |         const tables = [];
 9944 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
 9945 |         
 9946 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
 9947 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
 9948 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
 9949 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
 9950 | 
 9951 |         let match;
 9952 |         while ((match = fromRegex.exec(sql)) !== null) {
 9953 |             const name = match[1];
 9954 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
 9955 |                 tables.push(name);
 9956 |             }
 9957 |         }
 9958 |         
 9959 |         while ((match = metaRegex.exec(sql)) !== null) {
 9960 |             const name = match[1];
 9961 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
 9962 |                 tables.push(name);
 9963 |             }
 9964 |         }
 9965 | 
 9966 |         return tables;
 9967 |     }
 9968 | 
 9969 |     function convertToCSV(resultObj) {
 9970 |         const data = resultObj.data || [];
 9971 |         if (!data.length) return '';
 9972 |         
 9973 |         const tables = extractTableNames(resultObj.sql);
 9974 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
 9975 | 
 9976 |         const headers = Object.keys(data[0]);
 9977 |         const rows = data.map(row => 
 9978 |             headers.map(header => {
 9979 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
 9980 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
 9981 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
 9982 |             }).join(',')
 9983 |         );
 9984 |         return metaHeader + [headers.join(','), ...rows].join('\n');
 9985 |     }
